  ('diplomatic-a3078d07-moex-00612', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關司法權行使界限，下列敘述何者錯誤？', '["總統基於裁量權限所為之統治行為，非司法權應作合憲性審查之事項", "法律授權行政機關的專業判斷事項，其合法性之判斷不受司法審查", "人民基於志願組成之自治性團體，其本身設置之紀律規範，司法權不宜介入", "議會對其內部的議事活動與秩序維持，享有自治空間，司法權原則上應儘量尊重"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00613', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依憲法及地方制度法規定，有關地方自治，下列敘述何者錯誤？', '["地方自治團體具備公法人地位", "省為非地方自治團體", "內政部監督直轄市", "鄉鎮市已非地方自治團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00614', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '我國國際空間屢屢遭受中共的打壓，請問下列那一個國際組織臺灣仍然是會員？', '["聯合國", "世界衛生組織", "世界貿易組織", "國際民用航空組織"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00615', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '我國為防範境外敵對勢力之滲透干預，確保國家安全及社會安定，維護國家主權及自由民主憲政秩序，特 於2020年1月制定反滲透法。下列敘述或情形何者正確？', '["所謂境外敵對勢力指與我國交戰或武力對峙之國家、政治實體或團體，但不包括主張採取非和平手段危 害我國主權之國家、政治實體或團體", "任何人不得受滲透來源之指示、委託或資助，進行遊說法第2條所定之遊說行為。違反規定者，處5年 以下有期徒刑，得併科新臺幣1千萬元以下罰金", "任何人不得受滲透來源之指示、委託或資助，為總統副總統選舉罷免法第 43 條或公職人員選舉罷免法 第45條各款行為。違反規定者，處5年以下有期徒刑，得併科新臺幣1千萬元以下罰金", "臺灣人民共產黨2021年7月1日於臺南紅船基地公開慶祝中國共產黨成立100周年，違反反滲透法， 得處5年以下有期徒刑，併科新臺幣1千萬元以下罰金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
